beforeSaveCustomScript:
// =====================================================
// VERSIONE: 1.0.0
// DATA: 12-05-2026 22:18
// ENTITA:
// Contratto (Quote)
// TIPO:
// Before Save Custom Script
// =====================================================
//
// STORICO FORMULA
// -----------------------------------------------------
//
// 1.0.0
// -----------------------------------------------------
// FIX DEFINITIVO FORMULA CONTRATTO
//
// CORREZIONI:
//
// - Fix funzione round()
// - Espo usa math\round()
//
// AGGIUNTO:
//
// - Nome contratto automatico
// - Calcolo aliquota IVA
// - Calcolo minusPlus
// - Copia automatica indirizzi Account
//
// OBIETTIVO:
//
// Automatizzare:
//
// - nome contratto
// - iva
// - indirizzi
// - calcoli economici
//
// =====================================================



// =====================================================
// NOME CONTRATTO
// v1.1.0 25-05-2026
importoFinale = importoContratto;
if (importoFinale == null || importoFinale == 0) {
    importoFinale = amount;
}

clienteLabel = accountName;
if (clienteLabel == null || clienteLabel == '') {
    clienteLabel = clienteLabel;
}


// =====================================================
//
// FORMATO:
//
// DATA - NUMERO - CLIENTE - IMPORTO
//
// ESEMPIO:
//
// 2026-05-12 - CONTRATTO_00039 - MARIO ROSSI - €. 4500
//
// =====================================================

name = string\upperCase(
    string\concatenate(
        dateQuoted,
        ' - ',
        number,
        ' - ',
        clienteLabel,
        ' - €. ',
        importoFinale
    )
);



// =====================================================
// CALCOLO TAX RATE
// =====================================================
//
// taxAmount / amount
//
// RISULTATO:
//
// 0.22
// 0.10
// ecc.
//
// =====================================================

taxRate = math\round(
    (
        taxAmount * 100
    ) / amount,
    0
) / 100;



// =====================================================
// CALCOLO ALIQUOTA IVA
// =====================================================
//
// RISULTATO:
//
// 22
// 10
// ecc.
//
// =====================================================

aliquotaIVA = math\round(
    taxRate * 100,
    2
);



// =====================================================
// CALCOLO MARGINE
// =====================================================
//
// FORMULA:
//
// IMPORTO - PREZZO CODICE
//
// =====================================================

minusPlus = amount - (
    prezzoCodice / (
        1 + taxRate
    )
);



// =====================================================
// COPIA INDIRIZZO FATTURAZIONE
// =====================================================
//
// RECUPERATO DA:
//
// account
//
// =====================================================

billingAddressCity = account.billingAddressCity;

billingAddressCountry = account.billingAddressCountry;

billingAddressMap = account.billingAddressMap;

billingAddressPostalCode = account.billingAddressPostalCode;

billingAddressState = account.billingAddressState;

billingAddressStreet = account.billingAddressStreet;



// =====================================================
// COPIA INDIRIZZO INSTALLAZIONE
// =====================================================
//
// RECUPERATO DA:
//
// account
//
// =====================================================

shippingAddressCity = account.shippingAddressCity;

shippingAddressCountry = account.shippingAddressCountry;

shippingAddressMap = account.shippingAddressMap;

shippingAddressPostalCode = account.shippingAddressPostalCode;

shippingAddressState = account.shippingAddressState;

shippingAddressStreet = account.shippingAddressStreet;
